# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import androidx.appcompat.app.AppCompatActivity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast

class ShareActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        // Get the intent that was used to launch this activity from another app
        val intent = intent

        if (intent.type != null && (intent.type!!.startsWith("text/plain") || intent.type!!.startsWith("image/*"))) {
            when (intent.type!!) {
                "text/plain" -> handleText(intent)
                "image/*" -> handleImage(intent)
            }
        } else {
            Toast.makeText(this, "Unsupported content type", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleText(intent: Intent) {
        // Process the text data from the intent here
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        Toast.makeText(this, "Shared text: $sharedText", Toast.LENGTH_SHORT).show()
    }

    private fun handleImage(intent: Intent) {
        // Process the image data from the intent here
        val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        Toast.makeText(this, "Shared image URI: $imageUri", Toast.LENGTH_SHORT).show()
    }
}